      const wrap = sidebar.querySelector('.sidebar-wrapper-container');
      if (wrap && wrap.parentNode) {
        wrap.parentNode.insertBefore(badge, wrap.nextSibling);
      } else {
        sidebar.appendChild(badge);
      }
    }
  };

  /* ========== ίΡψίΛρ ========== */
  const boot = () => {
    initFakeDecrypt();
    initClueMaze();
    initBurnAfterReading();
    initQuizUnlock();
    initDualDecrypt();
    initDecryptSuccess();
    setTimeout(injectBadge, 1000);
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
  } else {
    boot();
  }

  document.addEventListener('pjax:complete', () => {
    setTimeout(() => {
      initFakeDecrypt();
      initClueMaze();
      initBurnAfterReading();
      initQuizUnlock();
      initDualDecrypt();
      // ί╛╜ύτι PJAX ίΡΟώΘΞόΨ░ό│ρίΖξ
      const existing = document.getElementById('hbe-badge');
      if (!existing) injectBadge();
      else renderBadge(loadAchievements());
    }, 200);
  });
})();

/* ============================================
