  const SLOT_PRIZES = [
    { match: 3, sym: 'ΏθΞΤ', prize: 'ΏθΟΚ ί░ΠίξΨΎ╝Β', msg: 'ϊ╕Κϊ╕ςόρ▒όκΔΎ╝Βϊ╗ΛίνσύγΕϋ┐Ρό░Φϊ╕ΞώΦβίαδΎ╜η' },
    { match: 3, sym: 'ΏθΞΜ', prize: 'ΏθΟΚ ί░ΠίξΨΎ╝Β', msg: 'όθιόςυϊ╕Κϋ┐ηΎ╝ΒώΖ╕ώΖ╕ύΦεύΦεί░▒όαψϊ╜ιΎ╜η' },
    { match: 3, sym: 'έφΡ', prize: 'έφΡ όαθόαθίξΨΎ╝Β', msg: 'ϊ╕Κόαθϋ┐ηύΠιΎ╝Βϊ╜ιϋλτί╣╕ϋ┐ΡόαθώΑΚϊ╕φϊ║ΗΎ╝Β' },
    { match: 3, sym: 'ΏθΞΑ', prize: 'ΏθΞΑ ίξ╜ϋ┐ΡίξΨΎ╝Β', msg: 'ίδδίΠ╢ϋΞΚΎ╝Βίξ╜ϋ┐ΡϋοΒόζξϊ║ΗίΥοΎ╜η' },
