    { match: 3, sym: 'ΏθΣΣ', prize: 'ΏθΣΣ ύγΘίΗιίξΨΎ╝Β', msg: 'ύγΘίΗιϊ╕Κϋ┐ηΎ╝Βϊ╗Λίνσϊ╜ιί░▒όαψίδ╜ύΟΜΎ╝Β' },
    { match: 3, sym: 'ΏθΤΟ', prize: 'ΏθΤΟ ώΤ╗ύθ│ίξΨΎ╝Β', msg: 'ώΤ╗ύθ│Ύ╝Βϊ╜ιίΠΣίνπϋ┤λϊ║ΗΎ╝ΒΎ╝Β' },
    { match: 3, sym: 'ΏθΟ░', prize: 'ΏθΟ░ ίν┤ίξΨΎ╝ΒΎ╝Β', msg: 'ΏθΟ░ΏθΟ░ΏθΟ░ ίν┤ίξΨΎ╝ΒΎ╝ΒΎ╝Βϊ╜ιίερί╝ΑύΟσύυΣίΡπΎ╝ΒΎ╝ΒΎ╝Β' },
    { match: 2, prize: 'ΏθΥψ ϊ╕νϋ┐ηΎ╝Β', msg: 'ϊ╕νϊ╕ςϊ╕Αόι╖Ύ╝ΝίΗΞόζξϊ╕Αόυκϋψ┤ϊ╕Ξίχγί░▒ϊ╕Κϊ╕ςϊ║ΗΎ╝Β' },
  ];

  const DAILY_FREE = 5;

  /* ========== localStorage ========== */
  const loadPoke = () => { try { return JSON.parse(localStorage.getItem(LS_POKE)) || { total: 0, head: 0, body: 0, feet: 0, milestone: 0 }; } catch { return { total: 0, head: 0, body: 0, feet: 0, milestone: 0 }; } };
