  const loadRps = () => { try { return JSON.parse(localStorage.getItem(LS_RPS)) || { wins: 0, losses: 0, ties: 0, total: 0, streak: 0, bestStreak: 0 }; } catch { return { wins: 0, losses: 0, ties: 0, total: 0, streak: 0, bestStreak: 0 }; } };
  const saveRps = (d) => { try { localStorage.setItem(LS_RPS, JSON.stringify(d)); } catch {} };

  const loadDice = () => { try { return JSON.parse(localStorage.getItem(LS_DICE)) || { wins: 0, losses: 0, total: 0, bestRoll: 0, mikuBestRoll: 0 }; } catch { return { wins: 0, losses: 0, total: 0, bestRoll: 0, mikuBestRoll: 0 }; } };
  const saveDice = (d) => { try { localStorage.setItem(LS_DICE, JSON.stringify(d)); } catch {} };

  const loadSlot = () => {
    try {
      const d = JSON.parse(localStorage.getItem(LS_SLOT));
      // όμΑόθξϊ╗ΛίνσόΩξόεθΎ╝ΝώΘΞύ╜χίΚσϊ╜βόυκόΧ░
      const today = new Date().toDateString();
      if (d && d.date === today) return d;
      return { date: today, remaining: DAILY_FREE, total: 0, plays: 0, bestPrize: '' };
    } catch { return { date: new Date().toDateString(), remaining: DAILY_FREE, total: 0, plays: 0, bestPrize: '' }; }
  };
  const saveSlot = (d) => { try { localStorage.setItem(LS_SLOT, JSON.stringify(d)); } catch {} };

  const mikuSay = (text, timeout) => {
    try {
      const tips = document.getElementById('live2d-tips');
      if (tips) {
        sessionStorage.setItem('live2d-priority', 99999);
        tips.innerHTML = text;
        tips.classList.add('live2d-tips-active');
        if (window.__mikuGameMsgTimer) clearTimeout(window.__mikuGameMsgTimer);
        window.__mikuGameMsgTimer = setTimeout(() => {
          tips.classList.remove('live2d-tips-active');
          sessionStorage.removeItem('live2d-priority');
          window.__mikuGameMsgTimer = null;
        }, timeout || 5000);
      }
    } catch {}
  };

  const spawnParticles = (originEl, count) => {
    count = count || 12;
    const rect = originEl.getBoundingClientRect();
    if (!rect) return;
    const cx = rect.left + rect.width / 2, cy = rect.top + rect.height / 2;
    const colors = ['#B19CD9', '#F8EEFF', '#7B68EE', '#E6D3FF', '#C4A0FF', '#FFFFFF', '#FFD700'];
    const ps = [];
    for (let i = 0; i < count; i++) {
      const p = document.createElement('div'); p.className = 'rps-particle';
      const angle = (Math.PI * 2 * i) / count + (Math.random() - 0.5) * 0.5;
      const dist = 40 + Math.random() * 50;
      const size = 4 + Math.random() * 4;
      const c = colors[Math.floor(Math.random() * colors.length)];
      p.style.cssText = `left:${cx}px;top:${cy}px;width:${size}px;height:${size}px;--dx:${Math.cos(angle) * dist}px;--dy:${Math.sin(angle) * dist}px;background:${c};box-shadow:0 0 4px ${c};`;
      ps.push(p);
    }
    const frag = document.createDocumentFragment();
    ps.forEach(p => frag.appendChild(p));
    document.body.appendChild(frag);
    setTimeout(() => ps.forEach(p => p.remove()), 700);
  };

  /* ========== A: ύΔφίΝ║ ========== */
  const ZONES = ['head', 'body', 'feet'];
  const ZONE_NAMES = { head:'ίν┤', body:'ϋ║τϊ╜Υ', feet:'ϋΕγ' };
  const ZONE_MSGS = {
    head: ['όΣ╕ίν┤ϊ╝γώΧ┐ϊ╕ΞώταύγΕΎ╝Β','ίΙτύλ░όΙΣίν┤ίΠΣΎ╝Νί╝Εϊ╣▒ϊ║ΗίΧοΎ╝Β','ίν┤έΑοίν┤όαψόΧΠόΕθώΔρϊ╜ΞίΧοΎ╝ΒhentaiΎ╝Β','ϊ╜ιίΗΞόΣ╕ίν┤όΙΣϋοΒύΦθό░Φϊ║ΗίΥοΎ╝Β','ϊ╜ιόαψόΣ╕ίν┤ύΜΓώφΦίΡΩΎ╝ΒΎ╝ΒώΔ╜όΣ╕ϊ║Η {total} όυκϊ║ΗΎ╝Β'],
    body: ['όαψέΑοόαψϊ╕Ξί░Πί┐Δύλ░ίΙ░ϊ║ΗίΡπέΑο','ί╣▓ίαδίΛρόΙΣίΣΑΎ╝Βί░Πί┐ΔόΙΣίΤυϊ╜ιΎ╝Β','ίΙτόΣ╕όΙΣΎ╝ΝόεΚϊ╗Αϊ╣Ιίξ╜όΣ╕ύγΕΎ╝Β','ίΗΞόΣ╕ύγΕϋψζόΙΣίΠψϋοΒόΛξϋφοϊ║ΗΎ╝ΒέΝΘέΩΠΎ╣ΠέΩΠέΝΘ','ίΠαόΑΒΎ╝Βϊ╜ιί╖▓ύ╗ΠόΣ╕ϊ║ΗόΙΣ {total} όυκϊ║ΗΎ╝Β'],
    feet: ['ίΣΑΎ╝ΒίΙτύλ░όΙΣύγΕϋΕγΎ╝Β','ίξ╜ύΩΤίΧΛίΥΙίΥΙίΥΙΎ╜η','ϋΕγέΑοϋΕγόεΚϊ╗Αϊ╣Ιίξ╜όΣ╕ύγΕΎ╝Β','ϊ╜ιϋ┐βόαψϊ╗Αϊ╣ΙίξΘόΑςύγΕύβΨίξ╜ίΧΛΎ╝Β','όΧΣίΣ╜ίΧΛϋ┐βώΘΝόεΚϋ╢│όΟπίΠαόΑΒΎ╝ΒΎ╝Β'],
  };

  const injectHitzones = () => {
    if (document.getElementById('live2d-hit-zone')) return;
    const plugin = document.getElementById('live2d-plugin');
    if (!plugin) return;
    const c = document.createElement('div'); c.id = 'live2d-hit-zone';
    ZONES.forEach(z => { const d = document.createElement('div'); d.id = `live2d-hit-${z}`; d.className = 'miku-hitzone'; d.dataset.zone = z; c.appendChild(d); });
    plugin.appendChild(c);
    c.addEventListener('click', (e) => {
      const div = e.target.closest('.miku-hitzone'); if (!div) return;
      const zone = div.dataset.zone; if (!zone) return;
      const data = loadPoke(); data.total++; data[zone]++;
      const msgs = ZONE_MSGS[zone];
      const idx = Math.min(Math.floor(data.total / 10), msgs.length - 1);
      let msg = msgs[idx].replace('{total}', data.total);
      if (data.total > 0 && data.total % 10 === 0 && data.total <= 50) msg += '<br><span style="font-size:11px;opacity:0.7;">ΏθΟψ ώΘΝύρΜύλΣΎ╝γ{total} όυκϋ╛╛όΙΡΎ╝Β</span>'.replace('{total}', data.total);
      data.milestone = idx; savePoke(data); mikuSay(msg);
      const el = document.getElementById('miku-poke-total'); if (el) el.textContent = data.total;
      ZONES.forEach(z2 => { const e2 = document.getElementById(`miku-poke-${z2}`); if (e2) e2.textContent = data[z2]; });
    });
  };

  /* ========== B: ύΝεόΜ│ ========== */
  const playRPS = (playerChoice, btnEl) => {
    btnEl.classList.add('miku-rps-flash'); spawnParticles(btnEl);
    setTimeout(() => btnEl.classList.remove('miku-rps-flash'), 120);
    const mikuChoice = RPS_CHOICES[Math.floor(Math.random() * 3)];
    let result; let win = 0, lose = 0, tie = 0;
    if (playerChoice === mikuChoice) { result = 'tie'; tie = 1; }
    else if (RPS_BEATS[playerChoice] === mikuChoice) { result = 'win'; win = 1; }
    else { result = 'lose'; lose = 1; }
    const data = loadRps(); data.total++; data.wins += win; data.losses += lose; data.ties += tie;
    if (win) { data.streak++; data.bestStreak = Math.max(data.bestStreak, data.streak); } else data.streak = 0;
    saveRps(data);
    const rpsEl = document.getElementById('miku-rps-score');
    if (rpsEl) rpsEl.innerHTML = `ϋΔε ${data.wins} / ϋ┤θ ${data.losses} / ί╣│ ${data.ties}${data.streak >= 2 ? `<br><span style="font-size:11px;color:var(--red-1);">ΏθΦξ ϋ┐ηϋΔε ${data.streak}</span>` : ''}`;

    const row = btnEl.closest('.miku-rps-row');
    const btns = row ? row.querySelectorAll('.miku-rps-choice') : [];
    const overlay = document.getElementById('miku-vs-overlay');
    if (!overlay || !row) return;
    btns.forEach(b => b.style.display = 'none'); overlay.style.display = 'flex';
    overlay.innerHTML = `<span style="font-size:32px;animation:vsPop 0.3s ease;">${RPS_EMOJI[playerChoice]}</span><span style="font-size:16px;font-weight:800;color:#F8EEFF;text-shadow:0 0 15px rgba(177,156,217,0.9);animation:vsPop 0.3s ease 0.1s both;">VS</span><span style="font-size:32px;animation:vsPop 0.3s ease 0.2s both;">${RPS_EMOJI[mikuChoice]}</span>`;
    setTimeout(() => {
      overlay.style.display = 'none'; overlay.innerHTML = ''; btns.forEach(b => b.style.display = '');
      const me = RPS_EMOJI[mikuChoice], mn = RPS_NAME[mikuChoice], pe = RPS_EMOJI[playerChoice], pn = RPS_NAME[playerChoice];
      let msg;
      if (win) msg = data.streak >= 3 ? `ϋ┐ηύ╗φϋ╡λ ${data.streak} όυκϊ║ΗέΑοϊ╜ιϊ╕Αίχγϊ╜εί╝Λϊ║ΗίΡπΎ╝ΒΏθαι` : [`ίΥ╝Ύ╝Βϊ╜ιίΘ║${pn}Ύ╝ΝόΙΣίΘ║${mn}... ύχΩϊ╜ιϋ╡░ϋ┐ΡΎ╝Β`,`ϊ╕ΞίΠψϋΔ╜Ύ╝Βϊ╜ιί▒ΖύΕ╢ϋ╡λϊ║ΗΎ╝θίΗΞόζξΎ╝Β`,`όΙΣόΚΞό▓κόεΚόΦ╛ό░┤ίΣλΎ╝Βϊ╜ιίΘ║${pn}${pe}ϋ╡λϊ║ΗϋΑΝί╖▓Ύ╝Β`][Math.floor(Math.random()*3)];
      else if (lose) msg = data.losses >= 10 ? `ϊ╜ιί╖▓ύ╗Πϋ╛Υύ╗βόΙΣ ${data.losses} όυκϊ║ΗΎ╝Νϋ┐αύΟσίΡΩΎ╝θΏθαΠ` : [`ίΥΙίΥΙΎ╝ΒόΙΣίΘ║${mn}${me}Ύ╝Νϊ╜ιϋ╛ΥίΧοΎ╜η`,`ί░▒ϋ┐βΎ╝θϋ┐ηόΙΣίΘ║${mn}ώΔ╜ϋ╡λϊ╕Ξϊ║ΗΎ╜η`,`ϋΠεϋΠεϋΠεΎ╝ΒϋοΒϊ╕ΞϋοΒόΙΣόΧβϊ╜ιίΧΛΎ╝θ`][Math.floor(Math.random()*3)];
      else msg = `ίΤοΎ╝θώΔ╜ίΘ║${mn}Ύ╝Νί╣│όΚΜΎ╝ΒίΗΞόζξΎ╝Β`;
      msg += `<br><span style="font-size:11px;opacity:0.6;">${pe} ${pn} vs ${me} ${mn}</span>`;
      mikuSay(msg, 6000);
    }, 1200);
  };

  /* ========== C: ώς░ίφΡ ========== */
  const playDice = () => {
    const btn = document.getElementById('miku-dice-btn'), pEl = document.getElementById('miku-dice-player'), mEl = document.getElementById('miku-dice-miku'), rEl = document.getElementById('miku-dice-result');
    if (!pEl || !mEl) return;
    rEl.textContent = 'ΏθΟ▓ όΟ╖ώς░ϊ╕φ...'; if (btn) btn.disabled = true;
    const rd = () => Array.from({length:3}, () => Math.floor(Math.random()*6)+1);
    const h = v => v.map(x => `<span class="miku-die">${x}</span>`).join('');
    let f = 0;
    const t = setInterval(() => {
      const fk = [1,2,3,4,5,6].sort(() => Math.random()-0.5).slice(0,3);
      const fk2 = [1,2,3,4,5,6].sort(() => Math.random()-0.5).slice(0,3);
      pEl.innerHTML = h(fk); mEl.innerHTML = h(fk2);
      pEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('rolling'));
      mEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('rolling'));
      f++;
      if (f >= 12) {
        clearInterval(t);
        const p = rd(), m = rd(), pm = Math.max(...p), mm = Math.max(...m);
        const pa = p.every(v => v === p[0]), ma = m.every(v => v === m[0]);
        pEl.innerHTML = h(p); mEl.innerHTML = h(m);
        if (pa) pEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('yahtzee'));
        if (ma) mEl.querySelectorAll('.miku-die').forEach(d => d.classList.add('yahtzee'));
        let res;
        if (pa && ma) res = pm >= mm ? 'w' : 'l';
        else if (pa) res = 'w';
        else if (ma) res = 'l';
        else res = pm > mm ? 'w' : pm < mm ? 'l' : 't';
        const data = loadDice(); data.total++;
        if (res === 'w') data.wins++; else if (res === 'l') data.losses++;
        data.bestRoll = Math.max(data.bestRoll, pm); data.mikuBestRoll = Math.max(data.mikuBestRoll, mm);
        saveDice(data);
        const se = document.getElementById('miku-dice-score');
        if (se) se.innerHTML = `ϋΔε ${data.wins} / ϋ┤θ ${data.losses}<br><span style="font-size:11px;opacity:0.6;">ϊ╜ιόεΑώτα ${data.bestRoll} | Miku όεΑώτα ${data.mikuBestRoll}</span>`;
        let msg;
        if (res === 'w') msg = pa ? `ΏθΟψ όΙΣόΟ╖ίΘ║ϊ║Ηϋ▒╣ίφΡΎ╝Βϊ╜ιϋ╛ΥίχγίΧοΎ╝Β` : [`ία┐ία┐Ύ╝Ν${pm} όψΦ ${mm}Ύ╝ΝόΙΣϋ╡λϊ║ΗΎ╜η`,`ί╣╕ϋ┐Ρίξ│ύξηύτβίερόΙΣϋ┐βϋ╛╣Ύ╝Β${pm} > ${mm}`][Math.floor(Math.random()*2)];
        else if (res === 'l') msg = ma ? `Ώθα▒ ϋ▒╣ίφΡΎ╝ΒΎ╝Βϋ┐βϊ╕ΞίΠψϋΔ╜Ύ╝Β` : [`ίΙΘΎ╝Ν${pm} όψΦ ${mm}Ύ╝Νϊ╜ιϋ┐Ρό░Φίξ╜ϋΑΝί╖▓`,`ϊ╜ιϋ╡λϊ║ΗέΑοϊ╜ΗόΙΣϊ╕Ξϊ╝γϋχνϋ╛ΥύγΕΎ╝Β`][Math.floor(Math.random()*2)];
        else msg = `ώΔ╜όαψ ${pm}Ύ╝Νί╣│όΚΜΎ╝ΒίΗΞόζξϊ╕Αί▒ΑΎ╝Β`;
        msg += `<br><span style="font-size:11px;opacity:0.6;">ϊ╜ι [${p.join(',')}] vs Miku [${m.join(',')}]</span>`;
        rEl.innerHTML = `<span style="font-size:13px;font-weight:700;color:var(--red-1);">${res === 'w' ? 'ΏθΟΚ ϊ╜ιϋ╡λϊ║ΗΎ╝Β' : res === 'l' ? 'Ώθαν ϊ╜ιϋ╛Υϊ║ΗΎ╝Β' : 'Ώθνζ ί╣│όΚΜΎ╝Β'}</span>`;
        mikuSay(msg, 6000); if (btn) btn.disabled = false;
      }
    }, 80);
  };

  /* ========== D: ϋΑΒϋβΟόε║ ========== */
  const getRandomSymbol = () => {
    const total = SLOT_SYMBOLS.reduce((s, x) => s + x.weight, 0);
    let r = Math.random() * total;
    for (const s of SLOT_SYMBOLS) { r -= s.weight; if (r <= 0) return s; }
    return SLOT_SYMBOLS[0];
  };

  const playSlot = () => {
    const data = loadSlot();
    if (data.remaining <= 0) {
      mikuSay('ϊ╗ΛίνσύγΕίΖΞϋ┤╣όυκόΧ░ύΦρίχΝίΧοΎ╜ηόαΟίνσίΗΞόζξίΡπΎ╝Β', 4000);
      return;
    }

    const btn = document.getElementById('miku-slot-btn');
    const reels = document.querySelectorAll('.miku-slot-reel');
    const prizeEl = document.getElementById('miku-slot-prize');
    if (!btn || !reels.length) return;
    btn.disabled = true; prizeEl.textContent = 'ΏθΟ░ ϋ╜υίΛρϊ╕φ...';

    // ίΛρύΦ╗
    let f = 0;
    const t = setInterval(() => {
      reels.forEach(r => {
        r.classList.add('rolling');
        r.textContent = SLOT_SYMBOLS[Math.floor(Math.random() * SLOT_SYMBOLS.length)].sym;
      });
      f++;
      if (f >= 15) {
        clearInterval(t);
        // ύ╗Υόηε
        const s1 = getRandomSymbol(), s2 = getRandomSymbol(), s3 = getRandomSymbol();
        reels[0].textContent = s1.sym; reels[1].textContent = s2.sym; reels[2].textContent = s3.sym;
        reels.forEach(r => r.classList.remove('rolling'));

        data.remaining--; data.total++;
        let prizeMsg = '';

        if (s1.sym === s2.sym && s2.sym === s3.sym) {
          // ϊ╕Κϋ┐η
          const p = SLOT_PRIZES.find(x => x.match === 3 && x.sym === s1.sym);
          prizeMsg = p ? p.prize : 'ΏθΟΚ ϊ╕Κϊ╕ςύδ╕ίΡΝΎ╝Β';
          const m = p ? p.msg : `${s1.sym} ϊ╕Κϋ┐ηΎ╝ΒίΟΚίχ│Ύ╝Β`;
          reels.forEach(r => r.classList.add('win-highlight'));
          spawnParticles(reels[0], 16);
          data.bestPrize = prizeMsg;
          mikuSay(m, 6000);
        } else if (s1.sym === s2.sym || s2.sym === s3.sym || s1.sym === s3.sym) {
          // ϊ╕νϋ┐η
          prizeMsg = 'ΏθΥψ ϊ╕νϋ┐ηΎ╝Β';
          mikuSay(`ί╖χϊ╕ΑύΓ╣ί░▒ϊ╕Κϊ╕ςϊ║ΗΎ╝ΒίΗΞόζξϊ╕ΑόυκΎ╜η`, 4000);
        } else {
          const msgs = [`${s1.sym} ${s2.sym} ${s3.sym}... ίΖρώΔ╜ϊ╕Ξϊ╕Αόι╖ϋψ╢`, `ϊ╗ΛίνσόΚΜό░Φϊ╕Ξίνςίξ╜ίΣλΎ╜η`, `ό▓κϊ║Μό▓κϊ║ΜΎ╝Νϊ╕Μόυκϊ╕Αίχγϊ╕φΎ╝Β`];
          mikuSay(msgs[Math.floor(Math.random()*msgs.length)], 4000);
        }

        data.plays++;
        saveSlot(data);

        prizeEl.innerHTML = prizeMsg ? `<span style="font-size:14px;font-weight:700;color:var(--red-1);">${prizeMsg}</span>` : '';
        const ce = document.getElementById('miku-slot-chances');
        if (ce) ce.textContent = `ΏθΟ░ ϊ╗ΛόΩξίΚσϊ╜β ${data.remaining} / ${DAILY_FREE} όυκ`;
        btn.disabled = false;
      }
    }, 80);
  };

  /* ========== ώζλόζ┐ό│ρίΖξ ========== */
  let widgetInjected = false;
  let currentGame = 'rps';

  const switchGame = (game) => {
    currentGame = game;
    ['rps','dice','slot'].forEach(g => {
      const el = document.getElementById(`miku-game-${g}`);
      if (el) el.style.display = g === game ? 'block' : 'none';
    });
    document.querySelectorAll('.miku-tab').forEach(t => t.classList.toggle('active', t.dataset.game === game));
  };
  window.__switchGame = switchGame;

  const injectSidebarWidget = () => {
    if (document.getElementById('miku-game-widget') || widgetInjected) return;
    const sidebar = document.querySelector('aside#sidebar');
    if (!sidebar) return;
    const poke = loadPoke(), rps = loadRps(), dice = loadDice(), slot = loadSlot();

    let h = '<div class="widget-wrap" id="miku-game-widget"><div class="widget-title" style="margin-bottom:12px;font-weight:700;color:var(--red-1);font-size:1.1em;display:flex;align-items:center;"><span style="margin-right:8px;">ΏθΟχ</span> Miku ϊ║ΤίΛρ</div><div class="widget" style="text-align:center;">';

    // όΙ│
    h += '<div style="margin-bottom:10px;"><div style="font-size:12px;font-weight:600;margin-bottom:6px;opacity:0.7;">ΏθΣΗ όΙ│ Miku</div><div class="miku-stat-row"><span>όΑ╗όυκόΧ░</span><span class="miku-stat-val" id="miku-poke-total">' + poke.total + '</span></div>';
    ZONES.forEach(z => h += '<div class="miku-stat-row"><span>' + ZONE_NAMES[z] + '</span><span class="miku-stat-val" id="miku-poke-' + z + '">' + poke[z] + '</span></div>');
    h += '</div><div style="height:1px;background:var(--red-5,rgba(255,228,228,0.3));margin:10px 0;"></div>';

    // Tabs
    h += '<div class="miku-tabs"><button class="miku-tab active" data-game="rps" onclick="window.__switchGame(\'rps\')">έεΛ ύΝεόΜ│</button><button class="miku-tab" data-game="dice" onclick="window.__switchGame(\'dice\')">ΏθΟ▓ ώς░ίφΡ</button><button class="miku-tab" data-game="slot" onclick="window.__switchGame(\'slot\')">ΏθΟ░ ϋΑΒϋβΟόε║</button></div>';

    // ύΝεόΜ│
    h += '<div id="miku-game-rps"><button id="miku-rps-btn" class="miku-game-btn" onclick="(()=>{var u=document.getElementById(\'miku-rps-ui\'),b=document.getElementById(\'miku-rps-btn\');if(!u||!b)return;var s=u.style.display!==\'block\';u.style.display=s?\'block\':\'none\';b.textContent=s?\'έεΨ ίΖ│ώΩφ\':\'ΏθΟχ ίΤΝ Miku ύΟσύΝεόΜ│\';})()">ΏθΟχ ίΤΝ Miku ύΟσύΝεόΜ│</button><div id="miku-rps-ui" style="display:none;margin-top:10px;"><div class="miku-rps-row" style="display:flex;justify-content:center;gap:10px;margin-bottom:6px;position:relative;">';
    h += '<button class="miku-rps-choice" data-choice="rock">έεΛ</button><button class="miku-rps-choice" data-choice="scissors">έεΝΎ╕Π</button><button class="miku-rps-choice" data-choice="paper">έεΜ</button>';
    h += '<div id="miku-vs-overlay" style="display:none;position:absolute;inset:0;align-items:center;justify-content:center;gap:12px;z-index:5;background:rgba(30,20,55,0.85);border-radius:12px;backdrop-filter:blur(4px);"></div></div>';
    h += '<div id="miku-rps-score" style="font-size:12px;opacity:0.7;">ϋΔε ' + rps.wins + ' / ϋ┤θ ' + rps.losses + ' / ί╣│ ' + rps.ties + '</div></div></div>';

    // ώς░ίφΡ
    h += '<div id="miku-game-dice" style="display:none;"><div class="miku-dice-section"><div class="miku-dice-label">ΏθπΣ ϊ╜ι</div><div class="miku-dice-area" id="miku-dice-player">ΏθΟ▓ ύΓ╣όΣΘώς░ί╝ΑίπΜ</div></div><div class="miku-dice-vs">έγκ</div><div class="miku-dice-section"><div class="miku-dice-label">ΏθΟν Miku</div><div class="miku-dice-area" id="miku-dice-miku">ΏθΟ▓ ύφΚί╛Ζϊ╕φ</div></div><div id="miku-dice-result" class="miku-dice-result"></div><button id="miku-dice-btn" class="miku-game-btn">ΏθΟ▓ όΣΘώς░ίφΡ</button><div id="miku-dice-score" style="font-size:12px;opacity:0.7;margin-top:4px;">ϋΔε ' + dice.wins + ' / ϋ┤θ ' + dice.losses + '</div></div>';

    // ϋΑΒϋβΟόε║
    h += '<div id="miku-game-slot" style="display:none;"><div class="miku-slot-machine"><div class="miku-slot-display">';
    for (let i = 0; i < 3; i++) h += '<div class="miku-slot-reel" id="miku-slot-reel-' + i + '">ΏθΟ░</div>';
    h += '</div><div id="miku-slot-prize" class="miku-slot-prize"></div>';
    h += '<button id="miku-slot-btn" class="miku-game-btn">ΏθΟ░ όΜΚόζΗΎ╝Β</button>';
    h += '<div id="miku-slot-chances" class="miku-slot-chances">ΏθΟ░ ϊ╗ΛόΩξίΚσϊ╜β ' + slot.remaining + ' / ' + DAILY_FREE + ' όυκ</div>';
    h += '</div></div>';

    h += '</div></div>';

    const tmp = document.createElement('div'); tmp.innerHTML = h;
    const widget = tmp.firstElementChild;
    const wa = sidebar.querySelector('.sidebar-widget');
    if (wa) wa.appendChild(widget);
    else { const w = sidebar.querySelector('.sidebar-wrapper-container'); if (w && w.parentNode) w.parentNode.insertBefore(widget, w.nextSibling); else sidebar.appendChild(widget); }

    widgetInjected = true;
    widget.querySelectorAll('.miku-rps-choice').forEach(b => b.addEventListener('click', e => playRPS(b.dataset.choice, b)));
    const db = widget.querySelector('#miku-dice-btn'); if (db) db.addEventListener('click', playDice);
    const sb = widget.querySelector('#miku-slot-btn'); if (sb) sb.addEventListener('click', playSlot);
  };

  const destroy = () => {
    ['live2d-hit-zone','miku-game-widget'].forEach(id => { const el = document.getElementById(id); if (el) el.remove(); });
    widgetInjected = false;
    document.querySelectorAll('.rps-particle').forEach(el => el.remove());
  };

  const init = () => { injectHitzones(); injectSidebarWidget(); };
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init); else init();
  window.addEventListener('pjax:send', destroy);
  window.addEventListener('pjax:complete', () => setTimeout(init, 150));
})();

/* ============================================
 * όΨΘύτιϋ┐╖ώδ╛ϋπμώΦΒύ│╗ύ╗θ έΑΦ ίχλόΙ╖ύτψϋΕγόευ
 *
 * ϋ┐╖ώδ╛ώΦΒύ▒╗ίηΜΎ╝γ
 *   1. όΩ╢ώΩ┤ώΦΒ (unlock_date) έΑΦ ίΙ░ϋ╛╛όΝΘίχγόΩξόεθόΚΞϋΔ╜ύεΜ
 *   2. ϋ┐δί║οώΦΒ (read_required) έΑΦ ϋψ╗ίχΝ N ύψΘόΨΘύτιόΚΞϋΔ╜ύεΜ
 *   3. ύοΒώαΖώΦΒ (forbid_start / forbid_end) έΑΦ όΝΘίχγόΩ╢ώΩ┤όχ╡ίΗΖϊ╕ΞϋΔ╜ύεΜ
 *
 * ϊ╜┐ύΦρόΨ╣ί╝Π (όΨΘύτι front-matter):
 *   unlock_date: 2030-06-01          # ίερόφνόΩξόεθίΡΟόΚΞϋΔ╜ύεΜ
 *   forbid_start: 2025-05-05         # ίερόφνόΩξόεθίΡΟϊ╕ΞϋΔ╜ύεΜ
 *   forbid_end: 2025-06-01           # ίερόφνόΩξόεθίΡΟόΚΞϋΔ╜ύεΜ
 *   όΙΨϋΑΖύ▓╛ύκχίΙ░ίΙΗώΤθΎ╝γ
 *   forbid_start: 2026-01-01 16:30
 *   forbid_end: 2026-03-15 15:00
 *   read_required: 3                # ϋψ╗ό╗κ N ύψΘόΚΞϋΔ╜ύεΜ
 *   mist_title: "ϋ┐╖ώδ╛ύγΕόιΘώλα"         # ϋΘςίχγϊ╣Κϋ┐╖ώδ╛όιΘώλα
 * ============================================ */

(() => {
  'use strict';

  /* ---- ί╖ξίΖ╖ίΘ╜όΧ░ ---- */
  const getArticleEl = () => document.querySelector(
    'article[data-unlock-date], article[data-read-required], article[data-forbid-start], article[data-forbid-end]'
  );

  const getReadCount = () => {
    try { return parseInt(localStorage.getItem('mist_read_count') || '0', 10); }
    catch { return 0; }
  };

  const setReadCount = (n) => {
    try { localStorage.setItem('mist_read_count', String(n)); } catch { /* noop */ }
  };

  const markArticleRead = (slug) => {
    try {
      const key = `mist_read_${slug}`;
      if (localStorage.getItem(key)) return;
      localStorage.setItem(key, '1');
      setReadCount(getReadCount() + 1);
    } catch { /* noop */ }
  };

  /** ϋπμόηΡόΩξόεθίφΩύυοϊ╕▓Ύ╝γόΦψόΝΒ "2026-01-01" όΙΨ "2026-01-01 16:30" όΙΨ ISO όι╝ί╝Π */
  const parseDate = (str) => {
    if (!str) return null;
    const dt = str.trim();
    // Hexo ίΠψϋΔ╜ϋ╛ΥίΘ║ ISO όι╝ί╝ΠίοΓ "2030-12-31T16:00:00.000Z" έΗΤ ύδ┤όΟξϊ╝ι Date όηΕώΑι
    if (dt.includes('T') || dt.includes('Z')) {
      const d = new Date(dt);
      return isNaN(d.getTime()) ? null : d;
    }
    // "2026-01-01 16:30" όι╝ί╝Π
    if (/^\d{4}-\d{2}-\d{2}\s+\d{1,2}:\d{2}$/.test(dt)) {
      return new Date(dt.replace(' ', 'T') + ':00');
    }
    // "2026-01-01" όι╝ί╝Π έΑΦ ϋπΗϊ╕║ί╜ΥίνσύγΕ 00:00
    return new Date(dt + 'T00:00:00');
  };

  /* ϋΟ╖ίΠΨϋ┐╖ώδ╛ύΛ╢όΑΒ */
  const getMistState = (el) => {
    const now = new Date();
    const unlockDate = parseDate(el.dataset.unlockDate);
    const forbidStart = parseDate(el.dataset.forbidStart);
    const forbidEnd = parseDate(el.dataset.forbidEnd);
    const readRequired = parseInt(el.dataset.readRequired || '0', 10);

    // ύοΒώαΖώΦΒΎ╝γ
    //   forbid_start ίΞΧύΜυϊ╜┐ύΦρ έΗΤ όφνόΩξόεθϊ╣ΜίΡΟό░╕ϊ╣ΖύοΒώαΖ
    //   forbid_start + forbid_end έΗΤ όφνόΩ╢ώΩ┤όχ╡ίΗΖύοΒώαΖ
    let inForbid = false;
    let forbidTarget = null;
    if (forbidStart && forbidEnd) {
      // όΩ╢ώΩ┤όχ╡ύοΒώαΖΎ╝γstart <= now < end
      inForbid = now >= forbidStart && now < forbidEnd;
      if (inForbid) forbidTarget = forbidEnd;
    } else if (forbidStart && !forbidEnd) {
      // ό░╕ϊ╣ΖύοΒώαΖΎ╝γnow >= start
      inForbid = now >= forbidStart;
      forbidTarget = null; // όΩιίΑΤϋχκόΩ╢
    }

    const timeLocked = unlockDate && now < unlockDate;
    const progressLocked = readRequired > 0 && getReadCount() < readRequired;

    return {
      locked: inForbid || timeLocked || progressLocked,
      inForbid,
      forbidTarget,
      timeLocked,
      progressLocked,
      unlockDate,
      forbidStart,
      forbidEnd,
      readRequired,
      readCount: getReadCount(),
    };
  };

  /* ϋχκύχΩίΚσϊ╜βόΩ╢ώΩ┤ */
  const getTimeRemaining = (target) => {
    const diff = target - new Date();
    if (diff <= 0) return { days: 0, hours: 0, minutes: 0, seconds: 0, total: 0 };
    return {
      days: Math.floor(diff / (1000 * 60 * 60 * 24)),
      hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
      minutes: Math.floor((diff / (1000 * 60)) % 60),
      seconds: Math.floor((diff / 1000) % 60),
      total: diff,
    };
  };

  /* όι╝ί╝ΠίΝΨόΩξόεθόα╛ύν║ */
  const formatDate = (d) => {
    if (!d) return '';
    return `${d.getFullYear()}.${String(d.getMonth()+1).padStart(2,'0')}.${String(d.getDate()).padStart(2,'0')}`;
  };

  const formatDateTime = (d) => {
    if (!d) return '';
    const h = String(d.getHours()).padStart(2, '0');
    const m = String(d.getMinutes()).padStart(2, '0');
    return `${formatDate(d)} ${h}:${m}`;
  };

  /* ό╕▓όθΥϋ┐╖ώδ╛ώΒχύ╜σ HTML */
  const renderOverlay = (state) => {
    const overlay = document.createElement('div');
    overlay.className = 'mist-overlay';

    let html = '<div class="mist-icon">ΏθΦχ</div>';

    const title = document.querySelector('article')?.dataset.mistTitle || 'ϋλτϋ┐╖ώδ╛ύυ╝ύ╜σύγΕόΨΘύτι';
    html += `<div class="mist-title">${title}</div>`;

    if (state.inForbid) {
      html += `<div class="mist-subtitle">έδΦ ϋ┐βύψΘόΨΘύτιίερί╜ΥίΚΞόΩ╢ώΩ┤ϊ╕ΞίΠψϋχ┐ώΩχ</div>`;
      if (state.forbidTarget) {
        // όεΚόΩ╢ώΩ┤ϋΝΔίδ┤ έΗΤ όα╛ύν║ίΑΤϋχκόΩ╢
        html += `<div class="mist-countdown" id="mist-forbid-timer">
          έδΦ ϊ╕ΞίΠψϋχ┐ώΩχόεθϋ┐αίΚσ<br>
          <span class="cd-num" id="cd-days">--</span> ίνσ
          <span class="cd-num" id="cd-hours">--</span> όΩ╢
          <span class="cd-num" id="cd-minutes">--</span> ίΙΗ
          <span class="cd-num" id="cd-seconds">--</span> ύπΤ
        </div>`;
      } else {
        // ό░╕ϊ╣ΖύοΒώαΖ έΗΤ όΩιίΑΤϋχκόΩ╢
        html += `<div class="mist-countdown">έδΦ ϋ┐βύψΘόΨΘύτιί╖▓ϋλτό░╕ϊ╣Ζί░ΒίΞ░</div>`;
      }
    }

    if (state.timeLocked) {
      const dateStr = formatDateTime(state.unlockDate);
      html += `<div class="mist-subtitle">ϋ┐βύψΘϋλτόΩ╢ώΩ┤ϋ┐╖ώδ╛ί░ΒίΞ░ϊ║Η<br>ί░Ηίερ ${dateStr} όΠφόβΥ</div>`;
      html += `<div class="mist-countdown" id="mist-countdown-timer">
        έΠ│ <span class="cd-num" id="cd-days">--</span> ίνσ
        <span class="cd-num" id="cd-hours">--</span> όΩ╢
        <span class="cd-num" id="cd-minutes">--</span> ίΙΗ
        <span class="cd-num" id="cd-seconds">--</span> ύπΤ
      </div>`;
    }

    if (state.progressLocked) {
      const pct = Math.min(100, Math.round((state.readCount / state.readRequired) * 100));
      html += '<div class="mist-subtitle">ΏθΥΨ ώεΑϋοΒώαΖϋψ╗ϋ╢│ίνθίνγύγΕόΨΘύτιόΚΞϋΔ╜όΠφί╝Αϋ┐╖ώδ╛</div>';
      html += `<div class="mist-progress">
        <span>ί╖▓ϋψ╗ <strong>${state.readCount}</strong> / ${state.readRequired}</span>
        <div class="mist-progress-bar">
          <div class="mist-progress-fill" style="width:${pct}%"></div>
        </div>
      </div>`;
      const remain = state.readRequired - state.readCount;
      if (remain > 0) {
        html += `<div class="mist-countdown">ΏθΥΨ ίΗΞϋψ╗ <strong>${remain}</strong> ύψΘίΞ│ίΠψϋπμώΦΒ</div>`;
      }
    }

    overlay.innerHTML = html;
    return overlay;
  };

  /* όδ┤όΨ░ίΑΤϋχκόΩ╢ */
  const updateCountdown = (target, prefix) => {
    const r = getTimeRemaining(target);
    const id = (name) => `${prefix}-${name}`;
    const daysEl = document.getElementById(id('days'));
    if (!daysEl) return r.total > 0;
    daysEl.textContent = String(r.days).padStart(2, '0');
    document.getElementById(id('hours')).textContent = String(r.hours).padStart(2, '0');
    document.getElementById(id('minutes')).textContent = String(r.minutes).padStart(2, '0');
    document.getElementById(id('seconds')).textContent = String(r.seconds).padStart(2, '0');
    return r.total > 0;
  };

  /* ---- ύδΣϋπΗίβρ ---- */
  const watchCountdown = (el, state) => {
    if (!state.locked) return;

    const target = state.inForbid ? state.forbidTarget : state.unlockDate;
    if (!target) return;

    // ίΙζίπΜίΝΨόα╛ύν║ (ID ίδ║ίχγϊ╕║ cd-days/cd-hours/cd-minutes/cd-seconds)
    updateCountdown(target, 'cd');

    const timer = setInterval(() => {
      // ώΘΞόΨ░ϋΟ╖ίΠΨίχΝόΧ┤ύΛ╢όΑΒΎ╝Ιίδιϊ╕║ίΠψϋΔ╜ϋ╖ρϋ┐Θϊ║Η forbid ύςΩίΠμΎ╝Κ
      const fresh = getMistState(el);
      if (!fresh.locked) {
        el.classList.add('mist-unlocked');
        clearInterval(timer);
        return;
      }
      const t = fresh.inForbid ? fresh.forbidTarget : fresh.unlockDate;
      updateCountdown(t, 'cd');
    }, 1000);
  };

  const watchProgress = (el, state) => {
    if (!state.progressLocked) return;
    const timer = setInterval(() => {
      const cur = getReadCount();
      if (cur >= state.readRequired) {
        el.classList.add('mist-unlocked');
        clearInterval(timer);
      }
    }, 2000);
  };

  /* ---- ίΙζίπΜίΝΨ ---- */
  const init = () => {
    const el = getArticleEl();
    if (!el) return;

    const state = getMistState(el);

    // ό▓κόεΚώΦΒ έΗΤ ϋπμώΦΒί╣╢ϋχ░ί╜Χί╖▓ϋψ╗
    if (!state.locked) {
      el.classList.add('mist-unlocked');
      const slug = el.id?.replace(/^post-/, '');
      if (slug) markArticleRead(slug);
      return;
    }

    // όΝΓϋ╜╜ϋ┐╖ώδ╛ώΒχύ╜σ
    const articleInner = el.querySelector('.article-inner');
    if (!articleInner) return;
    if (articleInner.querySelector('.mist-overlay')) return; // ώα▓όφλ PJAX ώΘΞίνΞ
    const overlay = renderOverlay(state);
    articleInner.style.position = 'relative';
    articleInner.appendChild(overlay);

    const slug = el.id?.replace(/^post-/, '');
    if (slug && !state.progressLocked) markArticleRead(slug);

    // ίΡψίΛρύδΣϋπΗίβρ
    watchCountdown(el, state);
    watchProgress(el, state);
  };

  /* ---- ίΡψίΛρ ---- */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  document.addEventListener('pjax:complete', () => setTimeout(init, 100));
})();

/* ============================================
 * Live2D όβ║ϋΔ╜ίε║όβψίψ╣ϋψζύ│╗ύ╗θΎ╝Ιίληί╝║ύΚΙΎ╝Κ
 * ίΛθϋΔ╜Ύ╝γ
 *   1. όΚΥίφΩόε║όΧΙόηεώΑΡίφΩϋ╛ΥίΘ║
 *   2. ίε║όβψόΕθύθξΎ╝γό╗γίΛρί║ΧώΔρήΑΒίΒεύΧβόΩ╢ώΧ┐ήΑΒό╖▒ίνεήΑΒώκ╡ώζλύ▒╗ίηΜ
 *   3. ίψ╣ϋψζόκΗόαθύσ║ώφΦό│Χόι╖ί╝Π
 *   4. ίχΙόΛνύ▓╛ύΒ╡όρκί╝Π έΑΦ όι╣όΞχίΞγίχλόδ┤όΨ░ώλΣύΟΘόΦ╣ίΠαόΑΒί║ο
 * ============================================ */

(() => {
  'use strict';

  const TYPING_SPEED = 60;
  const COOLDOWN = 800;
  const SCENE_PRIORITY = 50;

  let typing = false;
  let locked = false;
  let currentTimer = null;
  let lastText = '';
  let sceneTimer = null;
  let stayTimer = null;

  /* ----- όΚΥίφΩόε║όι╕ί┐Δ ----- */
  const typewrite = (el, text) => {
    if (currentTimer) clearInterval(currentTimer);
    typing = true;
    locked = true;
    el.textContent = '';
    let i = 0;
    currentTimer = setInterval(() => {
      el.textContent += text[i];
      i++;
      if (i >= text.length) {
        clearInterval(currentTimer);
        currentTimer = null;
        typing = false;
        setTimeout(() => { locked = false; }, COOLDOWN);
      }
    }, TYPING_SPEED);
  };

  const unlock = () => { locked = false; };

  const scene = {
    say(text, timeout = 6000) {
      const el = document.getElementById('live2d-tips');
      if (!el) return;
      sessionStorage.setItem('live2d-priority', SCENE_PRIORITY);
      el.innerHTML = text;
      el.classList.add('live2d-tips-active');
      if (sceneTimer) clearTimeout(sceneTimer);
      sceneTimer = setTimeout(() => {
        sessionStorage.removeItem('live2d-priority');
        el.classList.remove('live2d-tips-active');
        sceneTimer = null;
      }, timeout);
    },
  };

  /* ----- ίχΙόΛνύ▓╛ύΒ╡ ----- */
  let guardianState = null;

  const getGuardianState = (days) => {
    if (days <= 3) return { mood: 'happy', icon: 'ΏθΧ║', msg: 'όεΑϋ┐Σόδ┤όΨ░ϊ║ΗΎ╝Βίξ╜ί╝Αί┐ΔΎ╜ηϋοΒϊ╕Αϋ╡╖ίΛςίΛδίΥοΎ╝Β', face: 'όφμί╕╕' };
    if (days <= 7) return { mood: 'normal', icon: 'ΏθαΛ', msg: 'ϊ╕╗ϊ║║όεΑϋ┐Σϋ┐αίξ╜ίΡΩΎ╝θ', face: 'όφμί╕╕' };
    if (days <= 14) return { mood: 'worried', icon: 'Ώθαθ', msg: 'ί╖▓ύ╗Πϊ╕ΑίΣρό▓κόδ┤όΨ░ϊ║Η...ϊ╕╗ϊ║║όαψϊ╕Ξόαψίνςί┐βϊ║ΗΎ╝θ', face: 'όφμί╕╕' };
    if (days <= 30) return { mood: 'sad', icon: 'Ώθαη', msg: 'ί┐τίΞΛϊ╕ςόεΙϊ║ΗέΑοϊ╕╗ϊ║║ϊ╕ΞϋοΒόΙΣϊ║ΗίΡΩΎ╝θ', face: 'ϊ╝νί┐Δ' };
    return { mood: 'angry', icon: 'Ώθαν', msg: 'ϊ╕Αϊ╕ςόεΙϊ╕Ξόδ┤όΨ░Ύ╝Βίνςϋ┐ΘίΙΗϊ║ΗΎ╝ΒίΥ╝Ύ╝Β', face: 'ύΦθό░Φ' };
  };

  /* ----- όψΠίΣρϊ╕ΞίΡΝϊ╕╗ώλα ----- */
  const WEEKLY_THEMES = [
    { keywords: ['όΩΖϋκΝ','ί▒▒','ί╡σί▒▒','ό│░ί▒▒','Mount'], msg: 'ϋ┐βίΣρόαψόΩΖϋκΝίΣρΎ╝ΒόΔ│ύεΜύεΜϊ╕╗ϊ║║ύΙυϋ┐ΘύγΕόψΠϊ╕Αί║πί▒▒ ΏθΠΦΎ╕Π' },
    { keywords: ['όΛΑόεψ','Hexo','ίΚΞύτψ','όΡεύ┤λ','ίδ╛ί║Λ'], msg: 'όΛΑόεψίΣρΎ╝Βϋ┐βίΣρόΙΣϊ╗υόζξϋΒΛϋΒΛϊ╗μύιΒίΤΝόΛαϋΖ╛ ΏθδιΎ╕Π' },
    { keywords: ['ώγΠύυΦ','ί░ΠόΕθ','όΩξϋχ░','ύλΟύλΟί┐╡'], msg: 'όΩξί╕╕ίΣρΎ╝ΒίΡυίΡυϊ╕╗ϊ║║όεΑϋ┐ΣύγΕύλΟύλΟί┐╡ ΏθΥζ' },
    { keywords: ['ύΦ╡ί╜▒','ίΚπ','ύ║╕ώΤηί▒Μ','ώθσίδ╜'], msg: 'ί╜▒ϋπΗίΣρΎ╝Βϊ╕╗ϊ║║ίξ╜ίΔΠίΠΙύΗυίνεύεΜίΚπϊ║Η ΏθΥ║' },
    { keywords: ['όΧ░ίφο','ώταϋΑΔ','ϋχ║όΨΘ','Pandoc','ίφο'], msg: 'ίφοϊ╣ιίΣρΎ╝Βϊ╕Αϋ╡╖ίΛςίΛδίΠαί╝║ίΡπ ΏθΤς' },
  ];

  const getWeeklyTheme = () => {
    const week = Math.floor((Date.now() / 604800000) % WEEKLY_THEMES.length);
    return WEEKLY_THEMES[week];
  };

  const initWeeklyTheme = () => {
    const theme = getWeeklyTheme();
    const sidebar = document.querySelector('aside#sidebar');
    if (!sidebar) return;

    // ίερί╖▓ίΠΣϋκρύγΕώγΠόε║όΨΘύτιϊ╕φόΚ╛ϊ╕ΑύψΘίΝ╣ώΖΞϊ╕╗ώλαύγΕ
    fetch('/site-meta.json')
      .then(r => r.json())
      .then(() => {
        const el = document.createElement('div');
        el.style.cssText = 'margin-top:8px;padding:8px 12px;border-radius:8px;font-size:12px;text-align:center;background:rgba(255,78,106,0.06);border:1px solid rgba(255,78,106,0.15);opacity:0.8;';
        el.innerHTML = `ΏθΥΝ όευίΣρϊ╕╗ώλαΎ╝γ${theme.msg}`;
        const insertAfter = () => {
          const badge = document.getElementById('guardian-badge') || document.getElementById('miku-game-widget');
          if (badge && badge.parentNode) badge.parentNode.insertBefore(el, badge.nextSibling);
          else { const wa = sidebar.querySelector('.sidebar-widget'); if (wa) wa.appendChild(el); else sidebar.appendChild(el); }
        };
        setTimeout(insertAfter, 2000);
      })
      .catch(() => {});
  };

  const initGuardian = () => {
    fetch('/site-meta.json')
      .then(r => r.json())
      .then(data => {
        const state = getGuardianState(data.daysSinceLastUpdate);
        guardianState = state.mood;

        // ϊ╛πϋ╛╣όιΠόΙΨ footer όα╛ύν║ίΞγίχλύΛ╢όΑΒ
        const badge = document.createElement('div');
        badge.id = 'guardian-badge';
        badge.style.cssText =
          'margin-top:8px;padding:8px 12px;border-radius:8px;font-size:12px;' +
          'text-align:center;line-height:1.5;';

        if (state.mood === 'happy') {
          badge.style.background = 'rgba(76,175,80,0.1)';
          badge.style.border = '1px solid rgba(76,175,80,0.3)';
          badge.style.color = '#4caf50';
          badge.innerHTML = `ΏθΧ║ MikuΎ╝γϊ╕╗ϊ║║όεΑϋ┐Σί╛ΙίΜνί┐τίΣλΎ╝Β`;
        } else if (state.mood === 'sad') {
          badge.style.background = 'rgba(255,152,0,0.1)';
          badge.style.border = '1px solid rgba(255,152,0,0.3)';
          badge.style.color = '#ff9800';
          badge.innerHTML = `Ώθαη MikuΎ╝γίξ╜ϊ╣Ζό▓κόδ┤όΨ░ϊ║ΗέΑο`;
        } else if (state.mood === 'angry') {
          badge.style.background = 'rgba(244,67,54,0.1)';
          badge.style.border = '1px solid rgba(244,67,54,0.3)';
          badge.style.color = '#f44336';
          badge.innerHTML = `Ώθαν MikuΎ╝γί╖▓ύ╗Π ${data.daysSinceLastUpdate} ίνσό▓κόδ┤όΨ░ϊ║ΗΎ╝ΒΎ╝Β`;
        } else {
          badge.style.opacity = '0.6';
          badge.innerHTML = `ΏθΥζ ϊ╕Λόυκόδ┤όΨ░Ύ╝γ${data.daysSinceLastUpdate} ίνσίΚΞ`;
        }

        // ό│ρίΖξίΙ░ϊ╛πϋ╛╣όιΠ
        const injectBadge = () => {
          if (document.getElementById('guardian-badge')) return;
          const sidebar = document.querySelector('aside#sidebar');
          if (!sidebar) { setTimeout(injectBadge, 500); return; }
          const gameWidget = document.getElementById('miku-game-widget');
          if (gameWidget && gameWidget.parentNode) {
            gameWidget.parentNode.insertBefore(badge, gameWidget.nextSibling);
          } else {
            const wa = sidebar.querySelector('.sidebar-widget');
            if (wa) wa.appendChild(badge);
            else sidebar.appendChild(badge);
          }
        };
        setTimeout(injectBadge, 1500);

        // ώζη happy ύΛ╢όΑΒΎ╝ΝMiku ίερώοΨώκ╡ϊ╝γίνγϋψ┤ϊ╕ΑίΠξ
        if (state.mood !== 'happy' && window.location.pathname === '/') {
          setTimeout(() => scene.say(state.msg, 6000), 4000);
        }
      })
      .catch(() => {});
  };

  /* ----- ίΟθίε║όβψ ---- */
  const initScrollTrigger = () => {
    let hasTriggered = false;
    window.addEventListener('scroll', () => {
      if (hasTriggered) return;
      const scrollPercent = window.scrollY / (document.documentElement.scrollHeight - window.innerHeight);
      if (scrollPercent > 0.85) {
        hasTriggered = true;
        const msgs = guardianState === 'sad' ? ['ί▒ΖύΕ╢ύεΜίχΝϊ║ΗέΑοϋ░λϋ░λϊ╜ιόζξύεΜόΙΣ','ϋβ╜ύΕ╢ϊ╕╗ϊ║║ϊ╕Ξόδ┤όΨ░Ύ╝Νϊ╜Ηϋ┐αόεΚϊ╜ιίερ'] : ['ί▒ΖύΕ╢ίΖρώΔρύεΜίχΝϊ║ΗέΑού╗βϊ╜ιύΓ╣ϋ╡η ΏθΣΞ','ύεΜίχΝϊ║ΗΎ╝ΒϋοΒϊ╕ΞϋοΒύ┐╗ύ┐╗ίΖ╢ϊ╗ΨόΨΘύτιΎ╝θ'];
        scene.say(msgs[Math.floor(Math.random() * msgs.length)]);
      }
    }, { passive: true });
  };

  const initPageGreeting = () => {
    const path = window.location.pathname;
    let msg = '';
    if (path === '/' || path === '/index.html') {
      if (guardianState === 'angry') msg = 'ίΥ╝Ύ╝Βϊ╜ιόζξϊ║ΗΎ╝Νϊ╜Ηϊ╕╗ϊ║║ϊ╕Ξόδ┤όΨ░όεΚϊ╗Αϊ╣ΙύΦρέΑο';
      else if (guardianState === 'sad') msg = 'όυλϋ┐Οίδηίχ╢έΑοϋβ╜ύΕ╢ϋ┐βώΘΝίξ╜ϊ╣Ζό▓κίΠαίΝΨϊ║Η';
      else msg = 'όυλϋ┐Οίδηίχ╢Ύ╜η ύεΜύεΜϊ╕╗ϊ║║όεΑϋ┐ΣίΗβϊ║Ηϊ╗Αϊ╣ΙίΡπ';
    } else if (path.startsWith('/about')) msg = 'όΔ│ϊ║Ηϋπμϊ╕╗ϊ║║ίΡΩΎ╝θϊ╗Ψόαψϊ╕ςί╛ΙόεΚϋ╢μύγΕϊ║║ίΣλΎ╜η';
    else if (path.startsWith('/friend')) msg = 'όζξϋχνϋψΗϊ╕╗ϊ║║ύγΕόεΜίΠΜϊ╗υίΡπΎ╝Β';
    else if (path.startsWith('/gallery')) msg = 'όζξύεΜύεΜϊ╕╗ϊ║║όΜΞύγΕύΖπύΚΘΎ╝Β';
    else if (path.startsWith('/diary')) msg = 'ϊ╕╗ϊ║║ύγΕύλΟύλΟί┐╡ώΔ╜ίερϋ┐βώΘΝίΧοΎ╜η';
    else if (path.match(/^\/(\d{4})\//)) msg = guardianState === 'angry' ? 'ίΠΙόζξύεΜόΩπόΨΘύτιίΡΩέΑο' : 'ίΠΙόεΚόΨ░όΨΘύτιίΠψϊ╗ξύεΜίΧοΎ╜η';
    if (msg) setTimeout(() => scene.say(msg, 5000), 800);
  };

  const initNightCheck = () => {
    const hour = new Date().getHours();
    if (hour >= 23 || hour < 5) {
      setTimeout(() => { scene.say('ϋ┐βϊ╣Ιόβγϊ║Ηϋ┐αϊ╕ΞύζκΎ╝ΒϋοΒό│ρόΕΠϋ║τϊ╜ΥίΣΑ έγιΎ╕Π', 5000); }, 5000);
    }
  };

  const initStayTimer = () => {
    stayTimer = setTimeout(() => { scene.say('ύεΜϊ║Ηίξ╜ϊ╕Αϊ╝γίΕ┐ϊ║ΗίΣλΎ╝ΝϋοΒίΨζόζψό░┤ϊ╝ΣόΒψϊ╕ΜίΡΩΎ╜η', 5000); }, 120000);
  };

  /* ----- MutationObserver ----- */
  const initObserver = () => {
    const target = document.getElementById('live2d-tips');
    if (!target) { setTimeout(initObserver, 500); return; }

    const observer = new MutationObserver(() => {
      if (typing) return;
      const text = target.textContent.trim();
      if (!text || text === lastText) return;
      if (locked) { target.textContent = lastText; return; }
      lastText = text;
      typewrite(target, text);
    });

    observer.observe(target, { childList: true, subtree: true, characterData: true });

    const waifu = document.getElementById('waifu') || document.getElementById('live2d-plugin');
    if (waifu) { waifu.addEventListener('click', unlock); waifu.addEventListener('mouseenter', unlock); }
    target.addEventListener('click', unlock);
    console.log('[Live2D Scene] όβ║ϋΔ╜ίψ╣ϋψζύ│╗ύ╗θί╖▓ίΡψίΛρ έερ');
  };

  const boot = () => {
    initObserver();
    initScrollTrigger();
    initNightCheck();
    initStayTimer();
    initGuardian();
    initWeeklyTheme();
    setTimeout(initPageGreeting, 2000);
  };

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
})();

