/* ============================================
 * ύΧβϋρΑόΩ╢ύσ║ϋΔ╢ίδΛ έΑΦ ίχλόΙ╖ύτψ
 *
 * ίερόΨΘύτιώκ╡ϋψΕϋχ║ίΝ║ί▒Χύν║ήΑΝόζξϋΘςϋ┐ΘίΟ╗ύγΕϊ┐κόΒψήΑΞ
 * ϊ╜┐ύΦρόΨ╣ί╝Π (front-matter):
 *   time_capsule_date: 2026-12-25
 *   time_capsule_message: "ίεμϋψηϋΛΓύγΕϊ╜ιΎ╝Νϋ┐αίξ╜ίΡΩΎ╝θ"
 * ============================================ */

(() => {
  const init = () => {
    const article = document.querySelector('article.h-entry');
    if (!article) return;

    fetch('/time-capsule-data.json')
      .then(r => r.json())
      .then(capsules => {
        const today = new Date();
        const todayStr = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`;

        // όΚ╛ϊ╗ΛίνσίΝ╣ώΖΞύγΕϋΔ╢ίδΛ
        const match = capsules.find(c => c.date === todayStr);
        if (!match) return;

        // όΚ╛ϋψΕϋχ║ίΝ║ίχ╣ίβρ
        const comments = document.getElementById('comments') || document.querySelector('.comment-content, #waline-comment');
        if (!comments) return;

        const capsule = document.createElement('div');
        capsule.className = 'time-capsule';
        capsule.innerHTML = `
          <div class="time-capsule-title">ΏθΥε όΩ╢ύσ║ϋΔ╢ίδΛ έΑΦ "${match.title}"</div>
          <div class="time-capsule-message">${match.message}</div>
          <div class="time-capsule-date">ΏθΧ░Ύ╕Π ϋ┐βί░Βϊ┐κίΗβϊ║Οϋ┐ΘίΟ╗Ύ╝Νϊ║Ο ${todayStr} ί╝ΑίΡψ</div>
        `;

        comments.parentNode.insertBefore(capsule, comments);
      })
      .catch(() => {});
  };

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();
  document.addEventListener('pjax:complete', () => setTimeout(init, 200));
})();

