 * ϋΛ▒ίδφίψΕϋψφ έΑΦ ώγΠόε║ίΙΘόΞλ
 * ============================================ */

const GARDEN_REVERIES = [
  'όψΠύψΘόΨΘύτιώΔ╜όαψϊ╕ΑώλΩύπΞίφΡΎ╝Νϋ┐θόΩσϊ╝γίΠΣϋΛ╜ ΏθΝ▒',
  'ϋ┐βϊ╕ςϋΛ▒ίδφώΘΝΎ╝ΝϋΩΠύζΑϊ╕╗ϊ║║ϋ╡░ϋ┐ΘύγΕϋ╖ψήΑΒύεΜϋ┐ΘύγΕώμΟόβψ',
  'ώαΖϋψ╗όαψό╝τόφξΎ╝ΝίΗβϊ╜εόαψϋΑΧϋΑα',
  'όεΚόΩ╢ίΑβόεΑίξ╜ύγΕίΠΣύΟ░Ύ╝ΝόαψίερόΩπόΨΘύτιώΘΝόΚ╛ίΙ░όΨ░ύγΕϋΘςί╖▒',
  'ϋ┐βώΘΝύγΕόψΠϊ╕ΑύψΘόΨΘίφΩΎ╝ΝώΔ╜όαψόΩ╢ώΩ┤ώΧ┐ό▓│ώΘΝύγΕϊ╕Αύ▓Τό▓β',
  'ύεΜίχΝϊ║ΗΎ╝θώΓμί░▒ίΟ╗ϊ╕Μϊ╕ΑύψΘίΡπΎ╝ΝϋΛ▒ίδφώΘΝϋ┐αόεΚϋ╖ψϋοΒϋ╡░',
  '"όΓθί╖▓ί╛Αϊ╣Μϊ╕Ξϋ░ΠΎ╝ΝύθξόζξϋΑΖϊ╣ΜίΠψϋ┐╜"',
  'ί▒▒ίερώΓμώΘΝΎ╝ΝόΨΘίφΩίερϋ┐βώΘΝ',
  'ϋ░λϋ░λϊ╜ιόζξϋ┐βϊ╕ςϋπΤϋΡ╜ϋ╡░ϋ╡░ ΏθΞΔ',
];

window.__gardenReverie = () => {
  const msg = GARDEN_REVERIES[Math.floor(Math.random() * GARDEN_REVERIES.length)];
  try {
    const tips = document.getElementById('live2d-tips');
    if (tips) {
      sessionStorage.setItem('live2d-priority', 99999);
      tips.innerHTML = msg;
      tips.classList.add('live2d-tips-active');
      setTimeout(() => {
        tips.classList.remove('live2d-tips-active');
        sessionStorage.removeItem('live2d-priority');
      }, 5000);
    } else {
      alert(msg);
    }
  } catch {}
};
